function showMessage(e,t,n=null){const o=document.getElementById("messageArea");if(o.innerHTML=`<div class='message ${t?"success":"error"}'>${e}</div>`,t&&n){let t=10;const r="http://"+n+".local";o.innerHTML=`\n      <div class='message success'>\n        ${e}<br><br>\n        Make sure the device is connected to the <strong>same WiFi network</strong> as this computer.<br><br>\n        Redirecting to <a href="${r}">${n}.local</a> in <span id="countdown">${t}</span>s.\n      </div>\n    `;const s=setInterval(()=>{t--,document.getElementById("countdown").textContent=t,t<=0&&(clearInterval(s),window.location.href=r)},1e3)}else setTimeout(()=>{o.innerHTML=""},5e3)}function formatSize(e){return e<1024?e+" B":e<1048576?(e/1024).toFixed(1)+" KB":(e/1048576).toFixed(1)+" MB"}function formatSizeWithUnit(e){const t=["B","KB","MB","GB","TB"];let n,o=e,r=0;for(;o>=1024&&r<t.length-1;)o/=1024,r++;return n=0===r?o:o.toFixed(2),`${n} ${t[r]} `}var APP_VERSION="1.4.0";(function(){for(var e=location.pathname.split("/").pop()||"index.html",t=document.querySelectorAll(".menu a"),n=0;n<t.length;n++)t[n].getAttribute("href").replace("./","")===e&&t[n].classList.add("active")})(),function(){for(var e=document.querySelectorAll(".app-version"),t=0;t<e.length;t++)e[t].textContent=APP_VERSION}();